1	// Smoke test for the deployed apify-webhook edge function (US-016, US-017,
2	// US-018).
3	//
4	// Usage: bun run scripts/test/apify-webhook.ts
5	// Requires SUPABASE_URL, SUPABASE_ANON_KEY, APIFY_WEBHOOK_SECRET in .env.
6	//
7	// Covers the paths that don't need a live Apify run — the SUCCEEDED branch
8	// (which pulls a real dataset) is exercised end-to-end in the iteration's
9	// MCP verification, not here.
10	//
11	// Asserts:
12	//   1.  Missing X-Apify-Webhook-Secret → 401 UNAUTHORIZED
13	//   2.  Wrong secret → 401 UNAUTHORIZED (constant-time reject)
14	//   3.  Malformed JSON body with valid secret → 400 INVALID_JSON
15	//   4.  Missing required fields → 400 INVALID_REQUEST
16	//   5.  Unknown scrape_mode → 200 { skipped:'unsupported_scrape_mode' }
17	//       (defensive coverage for the catch-all branch; tiktok_profile,
18	//        ig_details, and ig_posts are all live)
19	//   6.  tiktok_profile + ACTOR.RUN.FAILED → 200 { inserted:true, duplicate:false }
20	//   7.  Replay same tiktok_profile run_id → 200 { inserted:false, duplicate:true }
21	//   8.  ig_details + ACTOR.RUN.FAILED → 200 { inserted:true, duplicate:false }
22	//   9.  Replay same ig_details run_id → 200 { inserted:false, duplicate:true }
23	//   10. ig_posts + ACTOR.RUN.FAILED → 200 { inserted:true, duplicate:false }
24	//   11. Replay same ig_posts run_id → 200 { inserted:false, duplicate:true }
25	
26	const supabaseUrl = process.env.SUPABASE_URL;
27	const anonKey = process.env.SUPABASE_ANON_KEY;
28	const webhookSecret = process.env.APIFY_WEBHOOK_SECRET;
29	if (!supabaseUrl || !anonKey || !webhookSecret) {
30	  console.error(
31	    "SUPABASE_URL, SUPABASE_ANON_KEY, and APIFY_WEBHOOK_SECRET are required in .env",
32	  );
33	  process.exit(1);
34	}
35	
36	const endpoint = `${supabaseUrl}/functions/v1/apify-webhook`;
37	// anon key is required by the Supabase gateway even for verify_jwt=false
38	// functions; the edge function itself validates X-Apify-Webhook-Secret.
39	const gatewayHeaders = {
40	  Authorization: `Bearer ${anonKey}`,
41	  apikey: anonKey,
42	};
43	
44	const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";
45	const SEED_INSTAGRAM_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111021";
46	const unique = Date.now();
47	
48	function basePayload(overrides: Record<string, unknown> = {}) {
49	  const runId = `us017_test_${unique}_${Math.random().toString(36).slice(2, 10)}`;
50	  return {
51	    eventType: "ACTOR.RUN.FAILED",
52	    resource: {
53	      id: runId,
54	      defaultDatasetId: `dataset_${runId}`,
55	      status: "FAILED",
56	      actId: "clockworks~tiktok-scraper",
57	    },
58	    social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID,
59	    scrape_mode: "tiktok_profile",
60	    run_id: runId,
61	    apify_finished_at: new Date().toISOString(),
62	    ...overrides,
63	  };
64	}
65	
66	async function postRaw(
67	  body: string | object,
68	  extraHeaders: Record<string, string> = {},
69	) {
70	  const res = await fetch(endpoint, {
71	    method: "POST",
72	    headers: {
73	      "Content-Type": "application/json",
74	      ...gatewayHeaders,
75	      ...extraHeaders,
76	    },
77	    body: typeof body === "string" ? body : JSON.stringify(body),
78	  });
79	  const data = await res.json().catch(() => null);
80	  return { status: res.status, data };
81	}
82	
83	function expect(label: string, cond: boolean, ctx: unknown) {
84	  if (!cond) {
85	    console.error(`FAIL ${label}:`, ctx);
86	    process.exit(1);
87	  }
88	  console.log(`ok — ${label}`);
89	}
90	
91	// 1. Missing secret header
92	{
93	  const r = await postRaw(basePayload());
94	  expect(
95	    "missing secret → 401 UNAUTHORIZED",
96	    r.status === 401 && r.data?.error === "UNAUTHORIZED",
97	    r,
98	  );
99	}
100	
101	// 2. Wrong secret header
102	{
103	  const r = await postRaw(basePayload(), {
104	    "X-Apify-Webhook-Secret": "definitely-not-the-real-secret",
105	  });
106	  expect(
107	    "wrong secret → 401 UNAUTHORIZED",
108	    r.status === 401 && r.data?.error === "UNAUTHORIZED",
109	    r,
110	  );
111	}
112	
113	// 3. Malformed JSON (valid secret)
114	{
115	  const r = await postRaw("{not json", {
116	    "X-Apify-Webhook-Secret": webhookSecret,
117	  });
118	  expect(
119	    "malformed json → 400 INVALID_JSON",
120	    r.status === 400 && r.data?.error === "INVALID_JSON",
121	    r,
122	  );
123	}
124	
125	// 4. Missing required fields
126	{
127	  const r = await postRaw(
128	    { eventType: "ACTOR.RUN.SUCCEEDED" },
129	    { "X-Apify-Webhook-Secret": webhookSecret },
130	  );
131	  expect(
132	    "missing fields → 400 INVALID_REQUEST",
133	    r.status === 400 && r.data?.error === "INVALID_REQUEST",
134	    r,
135	  );
136	}
137	
138	// 5. Unknown scrape_mode → defensive unsupported_scrape_mode short-circuit
139	{
140	  const r = await postRaw(
